const body = $input.first().json.body ?? $input.first().json;
const score = body.confluenceScore ?? 50;
const rec = body.recommendation ?? 'Neutro';
const pos = body.positive ?? [];
const neg = body.negative ?? [];

return [{
  json: {
    master: {
      summary: `Confluence ${score}/100 — ${rec}. ${body.explanation ?? ''}`.trim(),
      strengths: pos.slice(0, 5),
      weaknesses: neg.slice(0, 5),
      confluences: (body.intersections ?? []).map(i => i.pair ?? i.Pair).filter(Boolean),
      probability: score >= 70 ? 'Elevada' : score <= 30 ? 'Baixa' : 'Moderada',
      risk: score >= 80 ? 'Controlado' : 'Monitorar'
    },
    agentInsights: body.agentInsights ?? []
  }
}];
